const deal = $input.first().json;
const webhook = $('Webhook: Salesforce Sync Trigger').first().json.body;

// Determine operation: create vs update
const operation = deal.salesforce_opp_id ? 'update' : 'create';

// Build DAP timeline summary
let dapSummary = '';
if (webhook.dap_timeline) {
  try {
    const milestones = typeof webhook.dap_timeline === 'string' ? JSON.parse(webhook.dap_timeline) : webhook.dap_timeline;
    if (Array.isArray(milestones)) {
      dapSummary = milestones.map(m => {
        const status = m.complete ? '\u2713' : '\u25CB';
        return status + ' ' + (m.name || m.milestone || 'Milestone') + (m.date ? ' (' + m.date + ')' : '');
      }).join('\n');
    }
  } catch(e) { dapSummary = String(webhook.dap_timeline || ''); }
}

// Build Deal Highlights (DAP + current/future state + key stakeholder success criteria)
const highlights = [];
if (dapSummary) highlights.push('DAP TIMELINE:\n' + dapSummary);
if (webhook.current_state_org || webhook.current_state_activities || webhook.current_state_technology) {
  highlights.push('CURRENT STATE:\nOrg: ' + (webhook.current_state_org || 'N/A') + '\nActivities: ' + (webhook.current_state_activities || 'N/A') + '\nTechnology: ' + (webhook.current_state_technology || 'N/A'));
}
if (webhook.future_state_org || webhook.future_state_activities || webhook.future_state_technology) {
  highlights.push('FUTURE STATE:\nOrg: ' + (webhook.future_state_org || 'N/A') + '\nActivities: ' + (webhook.future_state_activities || 'N/A') + '\nTechnology: ' + (webhook.future_state_technology || 'N/A'));
}
if (webhook.key_stakeholder_success_criteria) {
  highlights.push('KEY STAKEHOLDER SUCCESS CRITERIA:\n' + webhook.key_stakeholder_success_criteria);
}

// Build risks string
let risksStr = '';
if (webhook.risks) {
  const risks = Array.isArray(webhook.risks) ? webhook.risks : [webhook.risks];
  risksStr = risks.join('\n- ');
  if (risksStr) risksStr = '- ' + risksStr;
}

// Map stage to Salesforce stage
const stageMap = {
  'discover': 'Discover',
  'qualify': 'Qualify',
  'prove': 'Prove',
  'negotiate': 'Negotiate',
  'close': 'Close'
};

const payload = {
  // Operation
  operation: operation,
  salesforce_opp_id: deal.salesforce_opp_id || null,

  // Required Opportunity fields
  company_name: deal.company_name || webhook.company_name,
  deal_id: webhook.deal_id,
  close_date: deal.close_date || webhook.close_date || null,
  stage: stageMap[webhook.deal_stage] || webhook.deal_stage || deal.deal_stage || 'Discover',
  deal_value: deal.deal_value_usd || null,

  // P2V2C2 scores
  pain_score: webhook.pain_score || 0,
  pain_description: webhook.pain_justification || '',
  power_score: webhook.power_score || 0,
  persons_with_power: webhook.champion_name || '',
  vision_score: webhook.vision_score || 0,
  vision_description: webhook.vision_justification || '',
  value_score: webhook.value_score || 0,
  value_notes: webhook.value_justification || '',
  change_score: webhook.change_score || 0,
  change_notes: webhook.change_justification || '',
  control_score: webhook.control_score || 0,
  control_notes: webhook.control_justification || '',

  // Other fields
  critical_activity_stage: webhook.critical_activity_stage || '',
  next_step: webhook.next_step || '',
  deal_highlights: highlights.join('\n\n---\n\n'),
  risks: risksStr,

  // Stakeholders
  champion_name: webhook.champion_name || '',
  champion_title: webhook.champion_title || '',
  executive_sponsor_name: webhook.executive_sponsor_name || '',
  executive_sponsor_title: webhook.executive_sponsor_title || '',

  // Metadata
  p2v2c2_total: webhook.p2v2c2_total || 0,
  trend_direction: webhook.trend_direction || 'stable',
  scored_at: new Date().toISOString()
};

return { json: payload };

const data = $('HTTP: Post to Make.com').first().json;
const payload = $('Code: Build Salesforce Payload').first().json;

function sq(v) { return v == null ? 'NULL' : "'" + String(v).replace(/'/g, "''") + "'"; }

const meta = JSON.stringify({
  operation: payload.operation,
  p2v2c2_total: payload.p2v2c2_total,
  company: payload.company_name
}).replace(/'/g, "''");

const sql = `INSERT INTO workflow_errors (workflow_id, workflow_name, node_name, error_message, deal_id, severity, metadata)
VALUES ('salesforce_sync', 'CW-06 Echo Sync', 'HTTP: Post to Make.com',
'Sync completed successfully',
${sq(payload.deal_id)}, 'info',
'${meta}')`;

return { json: { insert_sql: sql } };
